148	      customer: { yearsWithMHPCO: 0 },
149	      steps: [{
150	        op: "quote",
151	        items: [{ type: "sword", material: "steel", enchantment: 4, cursed: false }],
152	      }],
153	    });
154	    expect(result).toEqual({ results: [{ premium: 115 }] });
