176	  it.todo("customer with exactly 2 years → loyalty discount applies");
177	  it.todo("first insurance → 10% initial assessment surcharge per item");
178	  it.todo("follow-up contract (second quote+) → 15% discount on policy base");
179	
180	  // Modifier scope on multi-item policies
181	  it.todo("cursed sword + plain amulet → policy base 160 G + 50 G curse (item-scoped) → 210 G before fee");
182	
183	  // Rounding
184	  it.todo("premium that yields 197.5 G rounds up to 198 G (MHPCO's favor)");
185	  it.todo("payout that yields 350.5 G rounds down to 350 G (MHPCO's favor)");
186	
187	  // Integration examples
188	  it.todo("newcomer with cursed sword (steel, enchantment 3) → 165 G");
189	  it.todo("long-standing customer's second contract with cursed sword (enchantment 7) → 160 G");
