1	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	type Step = { op: "quote"; items: Item[] };
3	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
4	
5	type Customer = { yearsWithMHPCO: number };
6	
7	const PROCESSING_FEE = 5;
8	const FIRST_INSURANCE_SURCHARGE = 0.1;
9	const LOYALTY_DISCOUNT = 0.2;
10	const LOYALTY_YEARS_THRESHOLD = 2;
11	const CURSE_SURCHARGE = 0.5;
12	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
13	const HIGH_ENCHANTMENT_THRESHOLD = 5;
14	const COMPONENT_BLOCK_SIZE = 3;
15	const COMPONENT_BLOCK_PRICE = 60;
16	
17	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
18	  sword: 100,
19	  amulet: 60,
20	  staff: 80,
21	  potion: 40,
22	  rune: 25,
23	  moonstone: 25,
24	};
25	
26	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
27	
28	const basePremiumOf = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type];
29	
30	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
31	
32	const priceForComponentGroup = (type: string, count: number): number =>
33	  count === COMPONENT_BLOCK_SIZE
34	    ? COMPONENT_BLOCK_PRICE
35	    : count * BASE_PREMIUM_BY_TYPE[type];
36	
37	const countByType = (items: Item[]): Map<string, number> => {
38	  const counts = new Map<string, number>();
39	  for (const item of items) {
40	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
41	  }
42	  return counts;
43	};
44	
45	const sumBasePremiumsFor = (items: Item[]): number => {
46	  const mainItemsTotal = items
47	    .filter((item) => !isComponent(item))
48	    .reduce((sum, item) => sum + basePremiumOf(item), 0);
49	
50	  const componentsTotal = Array.from(countByType(items.filter(isComponent)))
51	    .reduce((sum, [type, count]) => sum + priceForComponentGroup(type, count), 0);
52	
53	  return mainItemsTotal + componentsTotal;
54	};
55	
56	// Item surcharges: each rule adds a percentage of the item's base premium when it applies.
57	const ITEM_SURCHARGE_RULES: { applies: (item: Item) => boolean; rate: number }[] = [
58	  { applies: (item) => item.cursed === true, rate: CURSE_SURCHARGE },
59	  { applies: (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD, rate: HIGH_ENCHANTMENT_SURCHARGE },
60	];
61	
62	const surchargeRateFor = (item: Item): number =>
63	  ITEM_SURCHARGE_RULES.reduce((rate, rule) => rate + (rule.applies(item) ? rule.rate : 0), 0);
64	
65	const itemSurchargesFor = (items: Item[]): number =>
66	  items.reduce((sum, item) => sum + basePremiumOf(item) * surchargeRateFor(item), 0);
67	
68	// Policy modifiers: each rule applies a +/- percentage of the policy base when its predicate holds.
69	const POLICY_MODIFIER_RULES: { applies: (customer: Customer) => boolean; rate: number }[] = [
70	  { applies: () => true, rate: FIRST_INSURANCE_SURCHARGE },
71	  { applies: (c) => c.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD, rate: -LOYALTY_DISCOUNT },
72	];
73	
74	const policyModifierRateFor = (customer: Customer): number =>
75	  POLICY_MODIFIER_RULES.reduce((rate, rule) => rate + (rule.applies(customer) ? rule.rate : 0), 0);
76	
77	const computePremium = (items: Item[], customer: Customer): number => {
78	  const policyBase = sumBasePremiumsFor(items);
79	  const itemSurcharges = itemSurchargesFor(items);
80	  const policyModifiers = policyBase * policyModifierRateFor(customer);
81	  return policyBase + itemSurcharges + policyModifiers + PROCESSING_FEE;
82	};
83	
84	// Rounds up to the nearest whole gold piece, in MHPCO's favor.
85	// Cleans float noise (e.g. 66.00000000000001) before ceiling.
86	const roundUpToGold = (amount: number): number =>
87	  Math.ceil(Math.round(amount * 1e6) / 1e6);
88	
89	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
90	  const results = scenario.steps.map((step) => ({
91	    premium: roundUpToGold(computePremium(step.items, scenario.customer)),
92	  }));
93	  return { results };
94	};
